function PurchasePricing(e){var t=this,n=($("#"+e),new Array);n.push({object:"hidItemKey[]",value:"pkey"});var r=n;this.tabID=e,this.updateDetail=function(e,t,a){{var n=$(e).closest(".transaction-detail-row");n.find('[name="hidItemKey[]"]').first()}for(i=0;i<t.length;i++)n.find("[name='"+t[i].object+"']").first().val(a.item[t[i].value]).change().blur();n.find('[name="itemName[]"]').first().val(decodeHTMLEntities(a.item.value))},this.rebindEl=function(){bindAutoCompleteForTransactionDetail("itemName[]",r,"ajax-item.php?action=searchData&itemtype=1&limit=25",t.updateDetail)},this.loadOnReady=function(){t.rebindEl()}}